pub(crate) fn translate_ar(en: &str) -> &str {
    lookup_ar(en).unwrap_or(en)
}

#[cfg(test)]
pub(crate) fn has_translation_ar(en: &str) -> bool {
    lookup_ar(en).is_some()
}

