pub(crate) fn translate_hi(en: &str) -> &str {
    lookup_hi(en).unwrap_or(en)
}

#[cfg(test)]
pub(crate) fn has_translation_hi(en: &str) -> bool {
    lookup_hi(en).is_some()
}

